object JSONObjectEscaper {
    fun escape(value: String): String {
        val escaped = buildString {
            append('"')
            value.forEach { ch ->
                when (ch) {
                    '\\' -> append("\\\\")
                    '"' -> append("\\\"")
                    '\b' -> append("\\b")
                    '\u000C' -> append("\\f")
                    '\n' -> append("\\n")
                    '\r' -> append("\\r")
                    '\t' -> append("\\t")
                    else -> {
                        if (ch.code < 0x20) {
                            append(String.format("\\u%04x", ch.code))
                        } else {
                            append(ch)
                        }
                    }
                }
            }
            append('"')
        }
        return escaped
    }
